using JLD2
using Test
using StaticArrays
using WaveGreen2D.Chebyshev: ChebyshevSeries, TransformedChebyshevSeries,
    gradient, hessian, contains


# This script contais the tests for the Chebyshev series that approximate Lâ‚پ and Lâ‚‚. The
# reference data is generated by the script at ../chebcoefs/chebseries_test_data.jl


@load "../src/chebyshev_series.jld2" Lâ‚پ_series Lâ‚‚_series


function u(x::SVector{3,Float64})
    A, B, H = x

    return SA[A, B, log(H)]
end


function âˆ‡u(x::SVector{3,Float64})
    _, _, H = x

    grad_u = one(MMatrix{3,3,Float64})
    grad_u[3, 3] = 1 / H

    return SMatrix(grad_u)
end


function Hu(x::SVector{3,Float64})
    _, _, H = x

    hess_u = zero(MArray{Tuple{3,3,3},Float64,3})
    hess_u[3, 3, 3] = -1 / H^2

    return SArray(hess_u)
end


Câ‚پ1 = Lâ‚پ_series[1]
Câ‚پ2 = TransformedChebyshevSeries(Lâ‚پ_series[2], u, âˆ‡u, Hu)
Câ‚پ3 = TransformedChebyshevSeries(Lâ‚پ_series[3], u, âˆ‡u, Hu)

Câ‚‚1 = TransformedChebyshevSeries(Lâ‚‚_series[1], u, âˆ‡u, Hu)
Câ‚‚2 = TransformedChebyshevSeries(Lâ‚‚_series[2], u, âˆ‡u, Hu)
Câ‚‚3 = TransformedChebyshevSeries(Lâ‚‚_series[3], u, âˆ‡u, Hu)
Câ‚‚4 = TransformedChebyshevSeries(Lâ‚‚_series[4], u, âˆ‡u, Hu)


function Câ‚پ(x::SVector{3,Float64})
    if contains(Câ‚پ1, x)
        return Câ‚پ1(x)
    elseif contains(Câ‚پ2, x)
        return Câ‚پ2(x)
    elseif contains(Câ‚پ3, x)
        return Câ‚پ3(x)
    else
        throw(DomainError(x))
    end
end


function Câ‚پ_gradient(x::SVector{3,Float64})
    if contains(Câ‚پ1, x)
        return gradient(Câ‚پ1, x)
    elseif contains(Câ‚پ2, x)
        return gradient(Câ‚پ2, x)
    elseif contains(Câ‚پ3, x)
        return gradient(Câ‚پ3, x)
    else
        throw(DomainError(x))
    end
end


function Câ‚پ_hessian(x::SVector{3,Float64})
    if contains(Câ‚پ1, x)
        return hessian(Câ‚پ1, x)
    elseif contains(Câ‚پ2, x)
        return hessian(Câ‚پ2, x)
    elseif contains(Câ‚پ3, x)
        return hessian(Câ‚پ3, x)
    else
        throw(DomainError(x))
    end
end


function Câ‚‚(x::SVector{3,Float64})
    if contains(Câ‚‚1, x)
        return Câ‚‚1(x)
    elseif contains(Câ‚‚2, x)
        return Câ‚‚2(x)
    elseif contains(Câ‚‚3, x)
        return Câ‚‚3(x)
    elseif contains(Câ‚‚4, x)
        return Câ‚‚4(x)
    else
        throw(DomainError(x))
    end
end


function Câ‚‚_gradient(x::SVector{3,Float64})
    if contains(Câ‚‚1, x)
        return gradient(Câ‚‚1, x)
    elseif contains(Câ‚‚2, x)
        return gradient(Câ‚‚2, x)
    elseif contains(Câ‚‚3, x)
        return gradient(Câ‚‚3, x)
    elseif contains(Câ‚‚4, x)
        return gradient(Câ‚‚4, x)
    else
        throw(DomainError(x))
    end
end


function Câ‚‚_hessian(x::SVector{3,Float64})
    if contains(Câ‚‚1, x)
        return hessian(Câ‚‚1, x)
    elseif contains(Câ‚‚2, x)
        return hessian(Câ‚‚2, x)
    elseif contains(Câ‚‚3, x)
        return hessian(Câ‚‚3, x)
    elseif contains(Câ‚‚4, x)
        return hessian(Câ‚‚4, x)
    else
        throw(DomainError(x))
    end
end


tol_L = 10^2 * eps()
tol_âˆ‡L = 10^4 * eps()
tol_HL = 10^6 * eps()


@testset "Lâ‚پ Chebyshev" begin
    @load "../test/data/l1_test_data.jld2" x1 L1 âˆ‡L1 HL1

    npoints = length(x1)

    C1 = Vector{Float64}(undef, npoints)
    C1g = Vector{Float64}(undef, npoints)
    C1h = Vector{Float64}(undef, npoints)

    âˆ‡C1 = Matrix{Float64}(undef, npoints, 3)
    âˆ‡C1h = Matrix{Float64}(undef, npoints, 3)

    HC1 = Array{Float64,3}(undef, npoints, 3, 3)

    for i in 1:npoints
        yâ‚پ = Câ‚پ(x1[i])
        yâ‚‚, âˆ‡yâ‚‚ = Câ‚پ_gradient(x1[i])
        yâ‚ƒ, âˆ‡yâ‚ƒ, Hyâ‚ƒ = Câ‚پ_hessian(x1[i])

        C1[i] = yâ‚پ
        C1g[i] = yâ‚‚
        C1h[i] = yâ‚ƒ
        âˆ‡C1[i, :] .= âˆ‡yâ‚‚
        âˆ‡C1h[i, :] .= âˆ‡yâ‚ƒ
        HC1[i, :, :] .= Hyâ‚ƒ
    end

    # Test if ChebyshevSeries, gradient and hessian return the same value of Lâ‚پ
    @test C1 == C1g
    @test C1 == C1h

    # Test if gradient and hessian return the same value of âˆ‡Lâ‚پ
    @test âˆ‡C1 == âˆ‡C1h

    @test all(isapprox.(L1, C1; rtol=tol_L, atol=tol_L))
    @test all(isapprox.(âˆ‡L1, âˆ‡C1; rtol=tol_âˆ‡L, atol=tol_âˆ‡L))
    @test all(isapprox.(HL1, HC1; rtol=tol_HL, atol=tol_HL))
end


